 10→import styles from "./CanvasEditor.module.css";
 11→import "./canvas.css";
 12→
 13→const FONT_BRUSHES = {
 14→    serif: {label: "Typewriter", fontFamily: "\"Courier New\", \"Lucida Console\", monospace", fontStyle: "normal", preview: "Ink Tape"},
 15→    handwritten: {label: "Brush Script", fontFamily: "\"Comic Sans MS\", \"Bradley Hand\", cursive", fontStyle: "normal", preview: "Wild Brush"},
 16→    bold: {label: "Street Bold", fontFamily: "\"Trebuchet MS\", \"Gill Sans\", sans-serif", fontStyle: "bold", preview: "Tagline"},
 17→    serifDisplay: {label: "Poster Serif", fontFamily: "Georgia, \"Times New Roman\", serif", fontStyle: "normal", preview: "Headline"}
 18→};
 19→
 20→const FONT_STYLE_MAP = {
 21→    serif: "serif",
 22→    handwritten: "handwritten",
 23→    bold: "bold",
 24→    mono: "serif",
 25→    serifDisplay: "serifDisplay"
 26→};
 27→
 28→const GRID_SIZE = 24;
 29→const CANVAS_MAX_WIDTH = 560;
 30→const MOBILE_BREAKPOINT = 820;
 31→const DOODLE_MIN_DISTANCE = 0.004;
 32→const DOODLE_SMOOTH_FACTOR = 0.3;
 33→const MIN_VIEWPORT_SCALE = 0.85;
 34→const MAX_VIEWPORT_SCALE = 3;
 35→const OBJECT_LIFT_MULTIPLIER = 1.03;
 36→
 37→const COLOR_PALETTES = [
 38→    {label: "Pastels", colors: ["#f8c8dc", "#f9e2af", "#b7e4c7", "#bde0fe", "#d7c3ff"]},
 39→    {label: "Earth", colors: ["#8c5e3c", "#b7794b", "#5a6d4d", "#4d6f75", "#2f3e46"]},
 40→    {label: "Neon", colors: ["#ff2d55", "#ff7a00", "#f7ff00", "#00e5ff", "#8a2be2"]}
 41→];
